634	ngx_uint_t
635	ngx_hash_key(u_char *data, size_t len)
636	{
637	    ngx_uint_t  i, key;
638	
639	    key = 0;
640	
641	    for (i = 0; i < len; i++) {
642	        key = ngx_hash(key, data[i]);
643	    }
644	
645	    return key;
646	}
